import (
	"encoding/hex"
	"fmt"
	"os"
)

type Config struct {
	ListenAddr    string
	DatabaseURL   string
	JWTSigningKey []byte
	AESMasterKey  []byte
}

func Load() (*Config, error) {
	listenAddr := os.Getenv("LISTEN_ADDR")
	if listenAddr == "" {
		listenAddr = ":8080"
	}

	dbURL := os.Getenv("DATABASE_URL")
	if dbURL == "" {
		return nil, fmt.Errorf("DATABASE_URL is required")
	}

	jwtKey := os.Getenv("JWT_SIGNING_KEY")
	if jwtKey == "" {
		return nil, fmt.Errorf("JWT_SIGNING_KEY is required")
	}

	aesHex := os.Getenv("AES_MASTER_KEY")
	if aesHex == "" {
		return nil, fmt.Errorf("AES_MASTER_KEY is required")
	}
	aesKey, err := hex.DecodeString(aesHex)
	if err != nil {
		return nil, fmt.Errorf("AES_MASTER_KEY must be hex-encoded: %w", err)
	}
	if len(aesKey) != 32 {
		return nil, fmt.Errorf("AES_MASTER_KEY must be 32 bytes (64 hex chars), got %d bytes", len(aesKey))
	}

	return &Config{
		ListenAddr:    listenAddr,
		DatabaseURL:   dbURL,
		JWTSigningKey: []byte(jwtKey),
		AESMasterKey:  aesKey,
	}, nil
}
"}

