{"file_path": "/Users/macbookpro/Projects/eaglepoint/w1t21/repo/backend/internal/middleware/csrf.go", "content": "package middleware

import (
	"crypto/rand"
	"encoding/hex"
	"net/http"

	"github.com/labstack/echo/v4"
	"github.com/ledgermint/platform/internal/dto"
)

func CSRF() echo.MiddlewareFunc {
	return func(next echo.HandlerFunc) echo.HandlerFunc {
		return func(c echo.Context) error {
			// Skip for safe methods
			if c.Request().Method == http.MethodGet ||
				c.Request().Method == http.MethodHead ||
				c.Request().Method == http.MethodOptions {
				return next(c)
			}

			// Skip CSRF for login and refresh (pre-auth)
			path := c.Request().URL.Path
			if path == "/api/auth/login" || path == "/api/auth/refresh" {
				return next(c)
			}

			cookie, err := c.Cookie("csrf_token")
			if err != nil {
				return echo.NewHTTPError(http.StatusForbidden, dto.ErrorResponse{
					Error: dto.ErrorDetail{
						Code:      dto.CodeForbidden,
						Message:   "missing CSRF cookie",
						RequestID: GetRequestID(c),
					},
				})
			}

			header := c.Request().Header.Get("X-CSRF-Token")
			if header == "" || header != cookie.Value {
				return echo.NewHTTPError(http.StatusForbidden, dto.ErrorResponse{
					Error: dto.ErrorDetail{
						Code:      dto.CodeForbidden,
						Message:   "CSRF token mismatch",
						RequestID: GetRequestID(c),
					},
				})
			}

			return next(c)
		}
	}
}

func GenerateCSRFToken() (string, error) {
	b := make([]byte, 32)
	if _, err := rand.Read(b); err != nil {
		return "", err
	}
	return hex.EncodeToString(b), nil
}

func SetCSRFCookie(c echo.Context, token string) {
	c.SetCookie(&http.Cookie{
		Name:     "csrf_token",
		Value:    token,
		Path:     "/",
		HttpOnly: false, // Must be readable by JS
		Secure:   false, // LAN - no TLS
		SameSite: http.SameSiteStrictMode,
	})
}
"}

