	}
	if user == nil {
		return nil, nil, dto.ErrInvalidCredentials
	}

	// Check if account is locked
	if user.IsLocked {
		if user.LockedUntil != nil && time.Now().Before(*user.LockedUntil) {
			return nil, nil, dto.ErrAccountLocked
		}
		// Lock expired, unlock
