	order, err := s.orderStore.GetByID(ctx, orderID)
	if err != nil {
		return err
	}
	if order == nil {
		return dto.ErrNotFound
	}

	tracking, _ := json.Marshal(req)
	return s.orderStore.UpdateFulfillment(ctx, orderID, tracking)
}

