import { useQuery } from '@tanstack/react-query';
import { Link } from 'react-router-dom';
import { listCollectibles } from '../api/collectibles';
import { formatCents } from '../utils/formatters';

export function CatalogPage() {
  const [page, setPage] = useState(1);

  const { data, isLoading } = useQuery({
    queryKey: ['collectibles', page],
    queryFn: () => listCollectibles(page).then((r) => r.data),
  });

  return (
    <div>
      <h1 className="text-2xl font-bold mb-6">Catalog</h1>

      {isLoading ? (
        <p className="text-gray-500">Loading...</p>
      ) : (
        <>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
            {data?.data?.map((item) => (
              <Link
                key={item.id}
                to={`/catalog/${item.id}`}
                className="bg-white p-4 rounded-lg shadow-sm border hover:shadow-md transition-shadow"
              >
                {item.image_url ? (
                  <img src={item.image_url} alt={item.title} className="w-full h-48 object-cover rounded mb-3" />
                ) : (
                  <div className="w-full h-48 bg-gray-100 rounded mb-3 flex items-center justify-center text-gray-400">
                    No image
                  </div>
                )}
                <h3 className="font-medium text-gray-900 truncate">{item.title}</h3>
                <p className="text-sm text-gray-500 mt-1 line-clamp-2">{item.description}</p>
                <div className="flex justify-between items-center mt-3">
                  <p className="text-lg font-bold text-primary-700">
                    {formatCents(item.price_cents, item.currency)}
                  </p>
                  <span className="text-xs text-gray-400">{item.view_count} views</span>
                </div>
              </Link>
            ))}
          </div>

          {data && data.total_pages > 1 && (
            <div className="flex justify-center gap-2 mt-6">
              <button
                onClick={() => setPage((p) => Math.max(1, p - 1))}
                disabled={page <= 1}
                className="px-4 py-2 bg-white border rounded disabled:opacity-50"
              >
                Previous
              </button>
              <span className="px-4 py-2 text-sm text-gray-600">
                Page {page} of {data.total_pages}
              </span>
              <button
                onClick={() => setPage((p) => p + 1)}
                disabled={page >= data.total_pages}
                className="px-4 py-2 bg-white border rounded disabled:opacity-50"
              >
                Next
              </button>
            </div>
          )}
        </>
      )}
    </div>
  );
}
"}

