{"file_path": "/Users/macbookpro/Projects/eaglepoint/w1t21/repo/frontend/src/pages/NotificationPrefsPage.tsx", "content": "import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { getPreferences, updatePreferences } from '../api/notifications';
import { useState, useEffect } from 'react';

const TEMPLATE_SLUGS = [
  { slug: 'order_confirmed', label: 'Order Confirmed' },
  { slug: 'order_processing', label: 'Order Processing' },
  { slug: 'order_completed', label: 'Order Completed' },
  { slug: 'order_cancelled', label: 'Order Cancelled' },
  { slug: 'refund_approved', label: 'Refund Approved' },
  { slug: 'arbitration_opened', label: 'Arbitration Opened' },
  { slug: 'review_posted', label: 'Review Posted' },
];

export function NotificationPrefsPage() {
  const queryClient = useQueryClient();
  const [prefs, setPrefs] = useState<Record<string, boolean>>({});

  const { data } = useQuery({
    queryKey: ['notificationPrefs'],
    queryFn: () => getPreferences().then((r) => r.data),
  });

  useEffect(() => {
    if (data?.preferences) {
      setPrefs(data.preferences);
    }
  }, [data]);

  const mutation = useMutation({
    mutationFn: updatePreferences,
    onSuccess: () => queryClient.invalidateQueries({ queryKey: ['notificationPrefs'] }),
  });

  const toggle = (slug: string) => {
    const updated = { ...prefs, [slug]: !prefs[slug] };
    setPrefs(updated);
    mutation.mutate(updated);
  };

  return (
    <div className="max-w-lg mx-auto">
      <h1 className="text-2xl font-bold mb-6">Notification Preferences</h1>
      <div className="bg-white rounded-lg shadow-sm border divide-y">
        {TEMPLATE_SLUGS.map(({ slug, label }) => (
          <div key={slug} className="flex justify-between items-center p-4">
            <span className="text-sm text-gray-900">{label}</span>
            <button
              onClick={() => toggle(slug)}
              className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${
                prefs[slug] !== false ? 'bg-primary-600' : 'bg-gray-300'
              }`}
            >
              <span
                className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${
                  prefs[slug] !== false ? 'translate-x-6' : 'translate-x-1'
                }`}
              />
            </button>
          </div>
        ))}
      </div>
    </div>
  );
}
"}

