1	export function formatCents(cents: number, currency = 'USD'): string {
2	  return new Intl.NumberFormat('en-US', {
3	    style: 'currency',
4	    currency,
5	  }).format(cents / 100);
6	}
7	
8	export function formatDate(dateStr: string): string {
9	  return new Date(dateStr).toLocaleDateString('en-US', {
10	    year: 'numeric',
11	    month: 'short',
12	    day: 'numeric',
13	    hour: '2-digit',
14	    minute: '2-digit',
15	  });
16	}
17	
18	export function formatRelativeTime(dateStr: string): string {
19	  const now = new Date();
20	  const date = new Date(dateStr);
21	  const diffMs = now.getTime() - date.getTime();
22	  const diffMins = Math.floor(diffMs / 60000);
23	
24	  if (diffMins < 1) return 'just now';
25	  if (diffMins < 60) return `${diffMins}m ago`;
26	  const diffHours = Math.floor(diffMins / 60);
27	  if (diffHours < 24) return `${diffHours}h ago`;
28	  const diffDays = Math.floor(diffHours / 24);
29	  if (diffDays < 7) return `${diffDays}d ago`;
30	  return formatDate(dateStr);
31	}
